// Solution
function validateRoutePath(routePath) {
  const pathSegments = routePath.split('/');
  const validParameters = ['/users/:id', '/orders/:orderId'];
  for (let i = 1; i < pathSegments.length; i++) {
    const segment = pathSegments[i];
    if (!validParameters.includes(segment)) {
      return false;
    }
  }
  return true;
}
